      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a formula to move an unknown value to one side of the equals sign.",
      "anchor": "Moving a value across the equals sign by reversing its operation (e.g., multiplication becomes division).",
      "misconception": "Believing you can move a term across the equals sign without changing its mathematical operation."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that indicate how many times a base number is multiplied by itself.",
      "anchor": "The '2' in I²R, which means current multiplied by itself.",
      "misconception": "Confusing the square of a number (x²) with multiplying that number by two (x * 2)."
    },
    {
      "term": "Pythagoras' Theorem",
      "simpleDefinition": "A formula used to find the length of a missing side in a right-angled triangle (a² + b² = c²).",
      "anchor": "Calculating the hypotenuse (longest side) of a cable run or a power triangle.",
      "misconception": "Forgetting to square root the final sum to find the actual length of the side."
    },
    {
      "term": "SOHCAHTOA",
      "simpleDefinition": "A mnemonic used to remember the ratios for Sine, Cosine, and Tangent in trigonometry.",
      "anchor": "Using 'Opposite over Hypotenuse' to find a specific angle or side in a circuit diagram.",
      "misconception": "Using the wrong trigonometric function because the 'Opposite' and 'Adjacent' sides were misidentified."
    },
    {
      "term": "Mean",
      "simpleDefinition": "The mathematical average found by adding all values together and dividing by the total number of values.",
      "anchor": "Finding the average current load across three phases.",
      "misconception": "Assuming 'average' always refers to the middle number in a list (the median) rather than the calculated mean."
    },
    {
      "term": "Percentages",
      "simpleDefinition": "A way of expressing a value as a portion of 100.",
      "anchor": "Calculating a 3% or 5% maximum allowable voltage drop for a circuit.",
      "misconception": "Multiplying by the whole percentage number (e.g., 5) instead of its decimal equivalent (0.05) during a calculation."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the sign.",
    "Square it, sum it, then root it.",
    "Opposite over Hypotenuse.",
    "Divide by 100 to find the decimal factor."
  ],
  "misconceptionTargets": [
    "Moving a term across the equals sign without reversing the operation.",
    "Confusing squaring a number with doubling it.",
    "Mixing up the Adjacent and Opposite sides in trigonometry.",
    "Assuming all averages are calculated the same way."
  ]
